import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getChannels } from '../services/api';

const MOVIE_CATEGORIES = ['movies', 'films', 'peliculas', 'películas', 'cine', 'series', 'vod'];
const RADIO_CATEGORIES = ['radio', 'music', 'música'];

const isMovie = (cat) => MOVIE_CATEGORIES.some(m => cat?.toLowerCase().includes(m));
const isRadio = (cat) => RADIO_CATEGORIES.some(r => cat?.toLowerCase().includes(r));

const Home = () => {
  const [channels, setChannels] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [activeTab, setActiveTab] = useState('tv');

  useEffect(() => {
    getChannels({}).then(setChannels).catch(console.error).finally(() => setLoading(false));
  }, []);

  const filtered = channels.filter(c =>
    c.name.toLowerCase().includes(search.toLowerCase())
  );

  const tvChannels = filtered.filter(c => !isMovie(c.category) && !isRadio(c.category));
  const radioChannels = filtered.filter(c => isRadio(c.category));
  const movieChannels = filtered.filter(c => isMovie(c.category));

  // Obtener categorías únicas de TV para filtrar
  const tvCategories = ['Todos', ...new Set(tvChannels.map(c => c.category).filter(Boolean))];
  const [tvFilter, setTvFilter] = useState('Todos');

  const filteredTv = tvFilter === 'Todos' ? tvChannels : tvChannels.filter(c => c.category === tvFilter);

  const tabs = [
    { id: 'tv', label: '📺 TV', count: tvChannels.length },
    { id: 'movies', label: '🎬 Películas', count: movieChannels.length },
    { id: 'radio', label: '📻 Radio', count: radioChannels.length },
  ];

  const Card = ({ item }) => (
    <Link
      to={`/player/channel/${item.id}`}
      className="bg-gray-800 hover:bg-gray-700 rounded-xl p-4 flex flex-col items-center gap-3 transition-all hover:scale-105 hover:ring-2 hover:ring-red-600"
    >
      {item.logo ? (
        <img
          src={item.logo}
          alt={item.name}
          className="w-16 h-16 object-contain bg-white rounded-lg p-1"
          onError={(e) => { e.target.style.display = 'none'; }}
        />
      ) : (
        <div className="w-16 h-16 bg-gray-600 rounded-lg flex items-center justify-center text-2xl">
          {isRadio(item.category) ? '📻' : isMovie(item.category) ? '🎬' : '📺'}
        </div>
      )}
      <span className="text-sm font-medium text-center truncate w-full">{item.name}</span>
      <span className="text-xs text-gray-400 bg-gray-700 px-2 py-0.5 rounded-full truncate w-full text-center">{item.category}</span>
    </Link>
  );

  if (loading) return (
    <div className="flex justify-center items-center h-[70vh]">
      <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-red-600"></div>
    </div>
  );

  return (
    <div className="pb-10">
      {/* Hero */}
      <div className="bg-gradient-to-b from-gray-800 to-gray-900 px-6 py-10 mb-6 text-center">
        <h1 className="text-4xl font-bold mb-2">RaulFlix</h1>
        <p className="text-gray-400 mb-6">TV en vivo · Películas · Radio</p>
        <input
          type="text"
          placeholder="Buscar..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full max-w-md px-4 py-3 bg-gray-700 rounded-full border border-gray-600 focus:outline-none focus:border-red-600 text-white"
        />
      </div>

      {/* Tabs */}
      <div className="flex gap-2 px-6 mb-6">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`px-5 py-2 rounded-full text-sm font-medium transition-colors ${
              activeTab === tab.id ? 'bg-red-600 text-white' : 'bg-gray-700 hover:bg-gray-600 text-gray-300'
            }`}
          >
            {tab.label} <span className="opacity-70">({tab.count})</span>
          </button>
        ))}
      </div>

      {/* Filtro de categorías solo en TV */}
      {activeTab === 'tv' && (
        <div className="flex gap-2 px-6 mb-6 overflow-x-auto pb-2">
          {tvCategories.map(cat => (
            <button
              key={cat}
              onClick={() => setTvFilter(cat)}
              className={`px-3 py-1 rounded-full text-xs font-medium whitespace-nowrap transition-colors ${
                tvFilter === cat ? 'bg-white text-black' : 'bg-gray-700 hover:bg-gray-600 text-gray-300'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      )}

      {/* Contenido */}
      <div className="px-6">
        {activeTab === 'tv' && (
          filteredTv.length > 0 ? (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
              {filteredTv.map(c => <Card key={c.id} item={c} />)}
            </div>
          ) : (
            <div className="text-center py-16 text-gray-400">No hay canales de TV</div>
          )
        )}

        {activeTab === 'movies' && (
          movieChannels.length > 0 ? (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
              {movieChannels.map(c => <Card key={c.id} item={c} />)}
            </div>
          ) : (
            <div className="text-center py-16 text-gray-400">No hay películas disponibles</div>
          )
        )}

        {activeTab === 'radio' && (
          radioChannels.length > 0 ? (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-4">
              {radioChannels.map(c => <Card key={c.id} item={c} />)}
            </div>
          ) : (
            <div className="text-center py-16 text-gray-400">No hay radios disponibles</div>
          )
        )}
      </div>
    </div>
  );
};

export default Home;
